package com.chaobo.scm.supplier.application.asn.event;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.infrastructure.persistence.asn.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class TmsAsnEventConsumerApplicationService{private static final String CONSUMER="supplier-asn-tms";private final MasterDataEventConsumeLogPort inbox;private final AsnTransportFactMapper facts;private final AsnTransportTrailMapper trails;private final InboundEventPayloadStore payloads;public TmsAsnEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,AsnTransportFactMapper facts,AsnTransportTrailMapper trails,InboundEventPayloadStore payloads){this.inbox=inbox;this.facts=facts;this.trails=trails;this.payloads=payloads;}@Transactional public void consume(TmsAsnEvent event){var claim=inbox.claim("TMS",event.eventCode(),event.eventType(),CONSUMER,"TMS:"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"TMS ASN事件正在处理");payloads.save("TMS",event.eventCode(),CONSUMER,event);try{int status=switch(event.eventType()){case "TransportTaskCreated","WaybillAssigned"->1;case "TransportInTransit"->2;case "TransportArrived"->3;case "TransportException"->4;default->0;};if(status==0){inbox.markSucceeded("TMS",event.eventCode(),CONSUMER,true);return;}facts.upsert(event.asnId(),event.shipmentId(),event.waybillNo(),event.carrierCode(),status,event.node(),event.occurredAt(),event.exceptionCode(),event.exceptionReason(),event.sourceVersion());trails.insert(event.asnId(),event.shipmentId(),event.waybillNo(),status,event.node(),event.occurredAt(),event.exceptionCode(),event.exceptionReason(),event.sourceVersion(),event.eventCode());inbox.markSucceeded("TMS",event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure("TMS",event.eventCode(),event.eventType(),CONSUMER,"TMS:"+event.eventCode(),exception.getMessage());throw exception;}}}
